CREATE OR REPLACE FUNCTION fpa_get_kep_method_ref (as_memno char, ai_year bigint,ai_month bigint,ai_seq bigint) RETURNS varchar AS $body$
DECLARE

  ls_val sc_kep_t_monthly_receive.kep_method_ref%type;

BEGIN
  select kep_method_ref into STRICT ls_val
  from sc_kep_t_monthly_receive
 where (membership_no = as_memno)
  and (receive_year = ai_year)
  and (receive_month = ai_month)
  and (seq_no = ai_seq);

  if coalesce(ls_val::text, '') = '' then ls_val := '';end if;
  return trim(both ls_val);

exception
when too_many_rows then return null;
when no_data_found then return null;
when others then CALL spa_dberror('fpa_get_kep_method_ref,'||as_memno||'');
end;
